18: namespace Envoy {
19: namespace Extensions {
20: namespace Filters {
21: namespace Common {
22: namespace ExtAuthz {
23: 
24: /**
25:  * Constant values used for tracing metadata.
26:  */
27: struct TracingConstantValues {
28:   const std::string TraceStatus = "ext_authz_status";
29:   const std::string TraceUnauthz = "ext_authz_unauthorized";
30:   const std::string TraceOk = "ext_authz_ok";
31:   const std::string HttpStatus = "ext_authz_http_status";
32: };
33: 
34: using TracingConstants = ConstSingleton<TracingConstantValues>;
35: 
36: /**
37:  * Possible constant response code details values for a check call.
38:  */
39: struct ResponseCodeDetailsValues {
40:   // The ext_authz filter denied the downstream request/connection.
41:   const std::string AuthzDenied = "ext_authz_denied";
42:   // The ext_authz filter encountered a failure, and was configured to fail-closed.
43:   const std::string AuthzError = "ext_authz_error";
44:   // The ext_authz filter invalidated the CheckResponse and dropped the client request.
45:   const std::string AuthzInvalid = "ext_authz_invalid";
46: };
47: using ResponseCodeDetails = ConstSingleton<ResponseCodeDetailsValues>;
48: 
49: /**
50:  * Constant auth related HTTP headers. All lower case. This group of headers can
51:  * contain prefix override headers.
52:  */
53: class HeaderValues {
54: public:
55:   const char* prefix() const { return ThreadSafeSingleton<Http::PrefixValue>::get().prefix(); }
56: 
57:   const Http::LowerCaseString EnvoyAuthPartialBody{absl::StrCat(prefix(), "-auth-partial-body")};
58:   const Http::LowerCaseString EnvoyAuthHeadersToRemove{
59:       absl::StrCat(prefix(), "-auth-headers-to-remove")};
60:   const Http::LowerCaseString EnvoyAuthFailureModeAllowed{
61:       absl::StrCat(prefix(), "-auth-failure-mode-allowed")};
62: };
63: 
64: using Headers = ConstSingleton<HeaderValues>;
65: 
66: /**
67:  * Possible async results for a check call.
68:  */
69: enum class CheckStatus {
70:   // The request is authorized.
71:   OK,
72:   // The authz service could not be queried.
73:   Error,
74:   // The request is denied.
75:   Denied
76: };
77: 
78: using UnsafeHeader = std::pair<std::string, std::string>;
79: using UnsafeHeaderVector = std::vector<UnsafeHeader>;
80: /**
81:  * Authorization response object for a RequestCallback.
82:  *
83:  * Header mutations and query parameter mutations are not expected to already be validated by the
84:  * client before packing them into this struct (hence they are "unsafe").
85:  */
86: struct Response {
87:   // Call status.
88:   CheckStatus status;
89:   // A set of HTTP headers returned by the authorization server, that will be optionally appended
90:   // to the request to the upstream server.
91:   UnsafeHeaderVector headers_to_append;
92:   // A set of HTTP headers returned by the authorization server, will be optionally set
93:   // (using "setCopy") to the request to the upstream server.
94:   UnsafeHeaderVector headers_to_set;
95:   // A set of HTTP headers returned by the authorization server, will be optionally added
96:   // (using "addCopy") to the request to the upstream server.
97:   UnsafeHeaderVector headers_to_add;
98:   // A set of HTTP headers returned by the authorization server, will be optionally added
99:   // (using "addCopy") to the response sent back to the downstream client on OK auth
100:   // responses.
101:   UnsafeHeaderVector response_headers_to_add;
102:   // A set of HTTP headers returned by the authorization server, will be optionally set (using
103:   // "setCopy") to the response sent back to the downstream client on OK auth responses.
104:   UnsafeHeaderVector response_headers_to_set;
105:   // A set of HTTP headers returned by the authorization server, will be optionally added
106:   // (using "addCopy") to the response sent back to the downstream client on OK auth
107:   // responses only if the headers were not returned from the authz server.
108:   UnsafeHeaderVector response_headers_to_add_if_absent;
109:   // A set of HTTP headers returned by the authorization server, will be optionally set (using
110:   // "setCopy") to the response sent back to the downstream client on OK auth responses
111:   // only if the headers were returned from the authz server.
112:   UnsafeHeaderVector response_headers_to_overwrite_if_exists;
113:   // A set of HTTP headers consumed by the authorization server, will be removed
114:   // from the request to the upstream server.
115:   std::vector<std::string> headers_to_remove;
116:   // A set of query string parameters to be set (possibly overwritten) on the
117:   // request to the upstream server.
118:   Http::Utility::QueryParamsVector query_parameters_to_set;
119:   // A set of query string parameters to remove from the request to the upstream server.
120:   std::vector<std::string> query_parameters_to_remove;
121:   // Optional http body used only on denied response.
122:   std::string body;
123:   // Optional http status used only on denied response.
124:   Http::Code status_code{};
125: 
126:   // A set of metadata returned by the authorization server, that will be emitted as filter's
127:   // dynamic metadata that other filters can leverage.
128:   ProtobufWkt::Struct dynamic_metadata;
129: };
130: 
131: using ResponsePtr = std::unique_ptr<Response>;
132: 
133: /**
134:  * Async callbacks used during check() calls.
135:  */
136: class RequestCallbacks {
137: public:
138:   virtual ~RequestCallbacks() = default;
139: 
140:   /**
141:    * Called when a check request is complete. The resulting ResponsePtr is supplied.
142:    */
143:   virtual void onComplete(ResponsePtr&& response) PURE;
144: };
145: 
146: class Client {
147: public:
148:   // Destructor
149:   virtual ~Client() = default;
150: 
151:   /**
152:    * Cancel an inflight Check request.
153:    */
154:   virtual void cancel() PURE;
155: 
156:   /**
157:    * Request a check call to an external authorization service which can use the
158:    * passed request parameters to make a permit/deny decision.
159:    * @param callback supplies the completion callbacks.
160:    *        NOTE: The callback may happen within the calling stack.
161:    * @param request is the proto message with the attributes of the specific payload.
162:    * @param parent_span source for generating an egress child span as part of the trace.
163:    * @param stream_info supplies the client's stream info.
164:    */
165:   virtual void check(RequestCallbacks& callback,
166:                      const envoy::service::auth::v3::CheckRequest& request,
167:                      Tracing::Span& parent_span, const StreamInfo::StreamInfo& stream_info) PURE;
168: 
169:   /**
170:    * Returns streamInfo of the current request if possible. By default just return a nullptr.
171:    */
172:   virtual StreamInfo::StreamInfo const* streamInfo() const { return nullptr; }
173: };
174: 
175: using ClientPtr = std::unique_ptr<Client>;
176: 
177: } // namespace ExtAuthz
178: } // namespace Common
179: } // namespace Filters
180: } // namespace Extensions
181: } // namespace Envoy
