258: Http::FilterHeadersStatus Filter::decodeHeaders(Http::RequestHeaderMap& headers, bool end_stream) {
259:   Router::RouteConstSharedPtr route = decoder_callbacks_->route();
260:   const auto per_route_flags = getPerRouteFlags(route);
261:   skip_check_ = per_route_flags.skip_check_;
262:   if (skip_check_) {
263:     return Http::FilterHeadersStatus::Continue;
264:   }
265: 
266:   if (!config_->filterEnabled(decoder_callbacks_->streamInfo().dynamicMetadata())) {
267:     stats_.disabled_.inc();
268:     if (config_->denyAtDisable()) {
269:       ENVOY_STREAM_LOG(trace, "ext_authz filter is disabled. Deny the request.",
270:                        *decoder_callbacks_);
271:       decoder_callbacks_->streamInfo().setResponseFlag(
272:           StreamInfo::CoreResponseFlag::UnauthorizedExternalService);
273:       decoder_callbacks_->sendLocalReply(
274:           config_->statusOnError(), EMPTY_STRING, nullptr, absl::nullopt,
275:           Filters::Common::ExtAuthz::ResponseCodeDetails::get().AuthzError);
276:       return Http::FilterHeadersStatus::StopIteration;
277:     }
278:     return Http::FilterHeadersStatus::Continue;
279:   }
280: 
281:   request_headers_ = &headers;
282:   const auto check_settings = per_route_flags.check_settings_;
283:   buffer_data_ = (config_->withRequestBody() || check_settings.has_with_request_body()) &&
284:                  !check_settings.disable_request_body_buffering() &&
285:                  !(end_stream || Http::Utility::isWebSocketUpgradeRequest(headers) ||
286:                    Http::Utility::isH2UpgradeRequest(headers));
287: 
288:   max_request_bytes_ = config_->maxRequestBytes();
289:   if (buffer_data_) {
290:     ENVOY_STREAM_LOG(debug, "ext_authz filter is buffering the request", *decoder_callbacks_);
291: 
292:     allow_partial_message_ = check_settings.has_with_request_body()
293:                                  ? check_settings.with_request_body().allow_partial_message()
294:                                  : config_->allowPartialMessage();
295:     if (check_settings.has_with_request_body()) {
296:       max_request_bytes_ = check_settings.with_request_body().max_request_bytes();
297:     }
298:     if (!allow_partial_message_) {
299:       decoder_callbacks_->setDecoderBufferLimit(max_request_bytes_);
300:     }
301:     return Http::FilterHeadersStatus::StopIteration;
302:   }
303: 
304:   // Initiate a call to the authorization server since we are not disabled.
305:   initiateCall(headers);
306:   return filter_return_ == FilterReturn::StopDecoding
307:              ? Http::FilterHeadersStatus::StopAllIterationAndWatermark
308:              : Http::FilterHeadersStatus::Continue;
309: }
